CREATE VIEW `ads_short_account_device_info_view` (`product_id` COMMENT "产品id", `user_id` COMMENT "用户id", `app_ver` COMMENT "app版本号", `os_ver` COMMENT "操作系统版本", `device2` COMMENT "设备型号", `mt` COMMENT "设备类型", `last_login_tm` COMMENT "最后登录时间", `corever` COMMENT "corever")
COMMENT "VIEW" AS SELECT `dim`.`dim_short_video_account_device_info`.`product_id`, `dim`.`dim_short_video_account_device_info`.`user_id`, `dim`.`dim_short_video_account_device_info`.`app_ver`, `dim`.`dim_short_video_account_device_info`.`os_ver`, `dim`.`dim_short_video_account_device_info`.`device2`, `dim`.`dim_short_video_account_device_info`.`mt`, `dim`.`dim_short_video_account_device_info`.`last_login_tm`, `dim`.`dim_short_video_account_device_info`.`corever` AS `comment`
FROM `dim`.`dim_short_video_account_device_info`;